#include <stdio.h>
#include <stdlib.h>

long long factorial(int n, int M) {
    long long result = 1;
    for (int i = 2; i <= n; i++) {
        result = (result * i) % M;
    }
    return result;
}

long long power(long long a, long long b, int M) {
    long long result = 1;
    while (b > 0) {
        if (b & 1) {
            result = (result * a) % M;
        }
        a = (a * a) % M;
        b >>= 1;
    }
    return result;
}

long long modInverse(long long a, int M) {
    return power(a, M - 2, M);
}

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N, M, Q;
        scanf("%d %d %d", &N, &M, &Q);
        for (int i = 0; i < Q; i++) {
            int r;
            scanf("%d", &r);
            long long fN = factorial(N, M);
            long long fr = factorial(r, M);
            long long fNr = factorial(N - r, M);
            long long result = (fN * modInverse((fr * fNr) % M, M)) % M;
            printf("%lld\n", result);
        }
    }
    return 0;
}

