import java.util.Scanner;
public class Main {
    public static long factorial(int n, int M) {
        long result = 1;
        for (int i = 2; i <= n; i++) {
            result = (result * i) % M;
        }
        return result;
    }

    public static long power(long a, long b, int M) {
        long result = 1;
        while (b > 0) {
            if (b % 2 == 1) {
                result = (result * a) % M;
            }
            a = (a * a) % M;
            b >>= 1;
        }
        return result;
    }

    public static long modInverse(long a, int M) {
        return power(a, M - 2, M);
    }

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        int T = scanner.nextInt();
        while (T-- > 0) {
            int N = scanner.nextInt();
            int M = scanner.nextInt();
            int Q = scanner.nextInt();
            for (int i = 0; i < Q; i++) {
                int r = scanner.nextInt();
                long fN = factorial(N, M);
                long fr = factorial(r, M);
                long fNr = factorial(N - r, M);
                long result = (fN * modInverse((fr * fNr) % M, M)) % M;
                System.out.println(result);
            }
        }
    }
}

