function power(a, b, M) {
    let result = 1;
    while (b > 0) {
        if (b % 2 === 1) {
            result = (result * a) % M;
        }
        a = (a * a) % M;
        b = b >> 1;
    }
    return result;
}

function modInverse(a, M) {
    return power(a, M - 2, M);
}

